+export function OrderedList({ items }: { items: string[] }) {
+  const rows: string[] = [];
+  /* eslint-disable-next-line no-restricted-syntax -- the UI must preserve the server-provided order. */
+  for (const item of items) {
+    rows.push(item);
+  }
+  return <ol>{rows.map((item) => <li key={item}>{item}</li>)}</ol>;
+}
